/**
 * Generated by `createservice subscription.UpdateSubscriptionContextPaymentMethodService --type mutations`
 */
const dayjs = require('dayjs')
const get = require('lodash/get')

const conf = require('@open-condo/config')
const { GQLError, GQLErrorCode: { BAD_USER_INPUT, INTERNAL_ERROR } } = require('@open-condo/keystone/errors')
const { GQLCustomSchema } = require('@open-condo/keystone/schema')
const { getById, find } = require('@open-condo/keystone/schema')

const { NOT_FOUND } = require('@condo/domains/common/constants/errors')
const access = require('@condo/domains/subscription/access/UpdateSubscriptionContextPaymentMethodService')
const { SubscriptionPaymentAdapter } = require('@condo/domains/subscription/tasks/utils/SubscriptionPaymentAdapter')
const { SubscriptionContext } = require('@condo/domains/subscription/utils/serverSchema')

/**
 * List of possible errors, that this custom schema can throw
 * They will be rendered in documentation section in GraphiQL for this custom schema
 */
const ERRORS = {
    SUBSCRIPTION_CONTEXT_NOT_FOUND: {
        mutation: 'updateSubscriptionContextPaymentMethod',
        variable: ['data', 'subscriptionContextId'],
        code: BAD_USER_INPUT,
        type: NOT_FOUND,
        message: 'SubscriptionContext not found',
    },
    SUBSCRIPTION_PAYMENT_RECIPIENT_NOT_CONFIGURED: {
        mutation: 'updateSubscriptionContextPaymentMethod',
        code: BAD_USER_INPUT,
        type: NOT_FOUND,
        message: 'SUBSCRIPTION_PAYMENT_RECIPIENT is not configured',
    },
    ACQUIRING_INTEGRATION_NOT_FOUND: {
        mutation: 'updateSubscriptionContextPaymentMethod',
        code: BAD_USER_INPUT,
        type: NOT_FOUND,
        message: 'AcquiringIntegrationContext not found for subscription payment recipient',
    },
    CARD_TOKEN_DELETION_FAILED: {
        mutation: 'updateSubscriptionContextPaymentMethod',
        code: INTERNAL_ERROR,
        type: 'CARD_TOKEN_DELETION_FAILED',
    },
}

const UpdateSubscriptionContextPaymentMethodService = new GQLCustomSchema('UpdateSubscriptionContextPaymentMethodService', {
    types: [
        {
            access: true,
            type: 'input UpdateSubscriptionContextPaymentMethodInput { dv: Int!, sender: SenderFieldInput!, subscriptionContext: SubscriptionContextWhereUniqueInput!, bindingId: String }',
        },
        {
            access: true,
            type: 'type UpdateSubscriptionContextPaymentMethodOutput { id: String! }',
        },
    ],
    
    mutations: [
        {
            access: access.canUpdateSubscriptionContextPaymentMethod,
            schema: 'updateSubscriptionContextPaymentMethod(data: UpdateSubscriptionContextPaymentMethodInput!): UpdateSubscriptionContextPaymentMethodOutput',
            resolver: async (parent, args, context) => {
                const { data } = args
                const { subscriptionContext: subscriptionContextWhere, bindingId, dv, sender } = data
                const subscriptionContextId = subscriptionContextWhere.id

                const subscriptionContext = await getById('SubscriptionContext', subscriptionContextId)
                if (!subscriptionContext || subscriptionContext.deletedAt) {
                    throw new GQLError(ERRORS.SUBSCRIPTION_CONTEXT_NOT_FOUND, context)
                }

                const organizationId = subscriptionContext.organization
                const currentBindingId = subscriptionContext.bindingId

                if (bindingId === null && currentBindingId) {
                    const otherActiveContexts = await find('SubscriptionContext', {
                        organization: { id: organizationId },
                        bindingId: currentBindingId,
                        id_not: subscriptionContextId,
                        endAt_gte: dayjs().format('YYYY-MM-DD'),
                        deletedAt: null,
                    })

                    if (otherActiveContexts.length === 0) {
                        const recipientOrganizationId = conf['SUBSCRIPTION_PAYMENT_RECIPIENT']

                        if (!recipientOrganizationId) {
                            throw new GQLError(ERRORS.SUBSCRIPTION_PAYMENT_RECIPIENT_NOT_CONFIGURED, context)
                        }

                        const acquiringIntegrationContexts = await find('AcquiringIntegrationContext', {
                            organization: { id: recipientOrganizationId },
                            deletedAt: null,
                        })

                        if (acquiringIntegrationContexts.length === 0) {
                            throw new GQLError(ERRORS.ACQUIRING_INTEGRATION_NOT_FOUND, context)
                        }

                        const acquiringIntegrationContext = acquiringIntegrationContexts[0]
                        const acquiringIntegration = await getById('AcquiringIntegration', acquiringIntegrationContext.integration)

                        if (!acquiringIntegration || !acquiringIntegration.hostUrl) {
                            throw new GQLError(ERRORS.ACQUIRING_INTEGRATION_NOT_FOUND, context)
                        }

                        try {
                            await SubscriptionPaymentAdapter.deleteCardToken({
                                hostUrl: acquiringIntegration.hostUrl,
                                organizationId,
                                cardTokenId: currentBindingId,
                            })
                        } catch (error) {
                            const errorMessage = get(error, 'message') || 'Unknown error'
                            throw new GQLError({
                                ...ERRORS.CARD_TOKEN_DELETION_FAILED,
                                message: `Failed to delete card token: ${errorMessage}`,
                            }, context)
                        }
                    }
                }

                await SubscriptionContext.update(context, subscriptionContextId, {
                    dv,
                    sender,
                    bindingId,
                })

                return {
                    id: subscriptionContextId,
                }
            },
        },
    ],
    
})

module.exports = {
    UpdateSubscriptionContextPaymentMethodService,
    ERRORS,
}
